/**
 * Order validators — pure validation functions for order operations.
 *
 * All functions are pure: no side effects, no database calls.
 * Services fetch data and pass it in; validators make the decision.
 */

import type { CreateOrderInput, Order, OrderStatus } from '../models/order.js';
import type { User } from '../models/user.js';

/**
 * Valid status transitions for orders.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Validate that an order exists.
 */
export function validateOrderExists(
  order: Order | undefined,
  orderId: string,
): asserts order is Order {
  if (!order) {
    throw new Error(`Order not found: ${orderId}`);
  }
}

/**
 * Validate that a user exists (used during order creation).
 */
export function validateOrderUser(
  user: User | undefined,
  userId: string,
): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Validate that an order has at least one item.
 */
export function validateOrderItems(input: CreateOrderInput): void {
  if (input.items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Check if a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate that a status transition is allowed, throwing if not.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * User validators — pure validation functions for user operations.
 *
 * All functions are pure: no side effects, no database calls.
 * Services fetch data and pass it in; validators make the decision.
 */

import type { User } from '../models/user.js';

/**
 * Validate that a user exists.
 */
export function validateUserExists(
  user: User | undefined,
  userId: string,
): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Validate that an email is not already taken.
 * Used during user creation.
 */
export function validateEmailNotTaken(
  email: string,
  existingUser: User | undefined,
): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that an email is not in use by another user.
 * Used during user update (allows keeping the same email).
 */
export function validateEmailNotInUse(
  email: string,
  existingUser: User | undefined,
): void {
  if (existingUser) {
    throw new Error(`Email ${email} is already in use`);
  }
}

