  validateUserExists,
  validateEmailNotTaken,
  validateEmailNotInUse,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

describe('User Validators', () => {
  const mockUser: User = {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
  };

  describe('validateUserExists', () => {
    it('should not throw when user exists', () => {
      expect(() => validateUserExists(mockUser, 'user-1')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });
  });

  describe('validateEmailNotTaken', () => {
    it('should not throw when no existing user with email', () => {
      expect(() =>
        validateEmailNotTaken('new@example.com', undefined),
      ).not.toThrow();
    });

    it('should throw when email is already taken', () => {
      expect(() =>
        validateEmailNotTaken('alice@example.com', mockUser),
      ).toThrow('User with email alice@example.com already exists');
    });
  });

  describe('validateEmailNotInUse', () => {
    it('should not throw when no existing user with email', () => {
      expect(() =>
        validateEmailNotInUse('new@example.com', undefined),
      ).not.toThrow();
    });

    it('should throw when email is in use', () => {
      expect(() =>
        validateEmailNotInUse('alice@example.com', mockUser),
      ).toThrow('Email alice@example.com is already in use');
    });
  });
});

